INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-c5fb3965-moex-00101', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「專家認為，現代人之所以常覺得壓力很大、人生空轉，主要是因為太忙 碌，總想用最少的時間，完成最多的事情，久而久之，心理壓力連帶影響 到生理健康。從早上醒來一路忙到半夜，躺在床上還不放心地滑手機，太 多訊息占據腦海，事情似乎永遠做不完，手機的藍光刺激加上心情煩悶， 導致睡眠品質不良。然而，科學實驗證實，單單透過呼吸，把意識放在一 吸一呼間，覺察空氣正在進出身體的細微感受，全然觀照著慢慢地吸氣、 慢慢地吐氣，讓我們比較容易把注意力放在當下的此時此刻，對於正在發 生的任何經驗都如實接納。經由這麼簡單的方法，就能明顯地降低我們的 身心壓力。」 根據上文，下列選項何者可以降低身心壓力？', '["集中精神，維持工作品質", "增加大腦含氧量，提升效率", "調節呼吸，注意力放在當下", "放掉負面情緒，消除身心疲勞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00102', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「水庫蓄水後，底層壓力在水位上升時增加，在水位下降時減少，這種變 動可能誘發地震。再者，當水本身的壓力增加，地下的裂隙可能因水被壓 入而擴大，甚至產生新的裂隙，造成地殼不穩定。此外，水的作用也可能 減少地殼間的摩擦力，使原本瀕臨飽和應力邊緣的地殼提前誘發地震。」 這段文字旨在說明：', '["水庫集水區首重地震監測", "蓄水規模與地震頻率有關", "裂隙監測可減少地殼摩擦力", "水庫附近比較容易發生地震"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00103', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「記憶是一種高階的大腦功能，也是最廣為人知的認知能力。記憶是所有 學習的基石，因為它是我們儲存知識和處理知識的地方。我們的記憶會決 定哪些知識值得保留，並跟原先存在大腦的知識做連結。我們的記憶不同 於靜止不變的建築，它在吸收和理解新訊息的過程中也不斷在改變。」 根據上文，下列選項何者正確？', '["若排斥記憶的能力，就無法儲存與處理知識", "記憶的知識量與大腦的認知，互為正比關係", "反覆練習可以有效開發大腦，增加生活知識", "運用最高階的記憶力，過濾與淘汰無用知識"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00104', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「食物過剩，服務過剩，我們這個時代的全面過剩特質，是造成傳統廣告 式微的原因之一。因此，今天不可能再用三十秒的電視廣告行銷產品與觀 念，而是需要有說故事這項法寶，讓人們能融入其中，進而自行延伸發展， 寫出各自的結局，讓其成為自己的感受，達到產品認同與價值擴散。」 根據上文，下列選項何者最符合文意？', '["過剩的時代需減少產品消耗", "故事包裝可提高產品認同度", "複雜的世界更需要廣告行銷", "產品價值遠比廣告更具意義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00105', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「做為自由主義知識分子，胡適對政府及領導人一向不是順從的態度，他 的批判、反對也許溫和，但非常堅決。不過他了解政府並不等同於國家， 政府可以換，國家不能換。為了發言的公正和方便，不論政府如何邀請， 他都謝絕從政。可是當日本大軍壓境，國家在危急存亡的時候，他毅然銜 命出使美國，甘做『過河卒子』。」 根據上文，下列選項何者最符合文意？', '["知識分子應該順從政府，貢獻社會", "知識分子應該效忠政府，堅持立場", "知識分子要能夠站在國家的對立面", "知識分子要有肩負國家興亡的責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00106', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「臺灣傳統聚落，以廟宇作為共同生活中心，廟前廟埕通常也是唯一的公 共空間。『庭園』則是富豪在自家內部興建的休閒空間，阻隔了一般百姓。 現代『公園』則帶有公共的意涵。臺灣最早的公園是日治時期的『圓山公 園』，但『臺北公園』卻是第一個模仿歐洲風格的城市公園，因此又稱新 公園。當時新公園在樹蔭下放置椅凳、並設置露天表演台，都是西方公園 的特徵。」 根據上文，下列選項何者正確？', '["比起「圓山公園」，「臺北公園」成立時間較晚，故稱新公園", "因為信仰的需要，政府建廟並提供廟埕作為臺灣傳統聚落中心", "日本殖民政府透過公園的公共空間，打壓傳統士紳的私人庭園", "公園公共空間的設立，起源於歐洲，提供免費觀賞戲劇的演出"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00107', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「老車站重新整修後，不單是倚老賣老，努力把過往的建築風貌留住，還 想藉由昔時的採煤風情，展現這個小站的獨特性。但規劃者的能力也僅止 於此，一旦踏出前面的公路，旅人很快就被拉回現實，拉回某一衛星城市 的髒亂和失序。」 根據上文，老車站重新規劃後的問題是：', '["新車站的標新立異抹煞歷史的痕跡和價值", "整修後的車站和站前社區缺乏連結和對話", "數位化的車站與當地資訊化落後形成對比", "整體衛生環境髒亂不堪且未受到大家重視"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00108', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「詩不是拿來『讀懂』的，而是用來『感覺』的。有人說，詩是文學中的 貴族，它曖昧且充滿暗號；但詩也很奇妙，當我們讀詩時，將會重新回到 自己人生的某個片刻。」 根據上文，下列選項何者正確？', '["詩不是拿來「讀懂」的，所以一般人無須過度深究、也無須字斟句酌的 閱讀", "詩的「奇妙」之處，在於它能示現真實的畫面，讓每個人都來到作者人 生的某個時刻", "詩是用來「感覺」的，因此讀詩時必須調動讀者的心靈，以感性的態度 體會文字所傳遞的情感", "從「曖昧」、「暗號」等詞，可以知道讀詩需要智慧來解決謎團，所以 「貴族」才能解譯密碼"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00109', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '蘇軾曾寫過一篇小遊記，提及在惠州時，一回遊覽松風亭，不料才走到半 路就腳痠力乏，眼見亭子還在遠遠的林間，苦惱、痛苦不已。良久忽而轉 念，思及「此間有甚麼歇不得處？」一時豁然開朗，感覺自己像是咬住魚 餌的魚忽然掙脫魚鉤那般自在！ 根據上文，下列選項符合蘇軾想法的是：', '["人生行佇坐臥處處皆學問", "人總是高估自己能做到的", "有萬全準備，方可堅持到底", "不需執著，人生沒有那麼難"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00110', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「有人說，幽默像針線，只要靈活運用，就可以彌補事情的缺陷；而人生 好比走鋼索，幽默就是那根平衡桿。有人問我，幽默是天生的還是後天的。 我認為是後天的，只要用心為別人著想，有時候也有雅量調侃自己，就可 培養幽默感，讓身邊的人快樂。我更相信，正因為幽默有利他的成分，一 個處處要占上風的人，是不可能有幽默感，也不會欣賞幽默感的。」 根據上文，下列選項何者最符合文意？', '["用心設計過的幽默，比無心發想的幽默更利他", "幽默感可以後天養成，同理並換位思考很重要", "能容忍他人處處占上風，是培養幽默感的要件", "愛調侃自己的人勿勉強耍幽默，以免弄巧成拙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
